import React from 'react';
import ReactDOM from 'react-dom/client'; // note o '/client'

import Primeiro from './componentes/Primeiro';

// abaixo, é feita a renderização do conteudo do componente que foi definido no arquivo "componentes/primeiro"
ReactDOM.createRoot(document.getElementById('root')).render(<Primeiro/>);

// a linha abaixo vai fazer com que seja inserido o conteúdo no browser sem a insersão via componente
ReactDOM.createRoot(document.getElementById('root')).render(<h1>React</h1>);

